1	//! [`Registry`] - the in-memory roster of connected agents, grouped by project.
2	//!
3	//! Ephemeral by design: the registry tracks *currently connected* agents, so it
4	//! is never persisted. A daemon restart correctly starts with an empty roster
5	//! that refills as agents reconnect. [`crate::Store`] owns one `Registry` and
6	//! is the only caller; the projection of the roster lives there too.
7	
8	use std::collections::HashMap;
9	use std::time::{Duration, SystemTime};
10	
11	use crate::model::Agent;
12	
13	/// Per-project agent rosters. The outer key is the raw project id; the inner
14	/// key is the agent's opaque connection key.
15	#[derive(Default)]
16	pub(crate) struct Registry {
17	    by_project: HashMap<i64, HashMap<String, Agent>>,
18	}
19	
20	impl Registry {
21	    /// Record activity from `key` in `project`, registering it on first sight.
22	    /// Returns `true` if this call newly registered the agent.
23	    pub(crate) fn touch(&mut self, project: i64, key: &str) -> bool {
24	        let agents = self.by_project.entry(project).or_default();
25	        let now = SystemTime::now();
26	        match agents.get_mut(key) {
27	            Some(agent) => {
28	                agent.last_seen = now;
29	                false
30	            }
31	            None => {
32	                agents.insert(
33	                    key.to_string(),
34	                    Agent {
35	                        key: key.to_string(),
36	                        name: key.to_string(),
37	                        status: String::new(),
38	                        first_seen: now,
39	                        last_seen: now,
40	                    },
41	                );
42	                true
43	            }
44	        }
45	    }
46	
47	    /// Drop agents in `project` not seen within `max_idle`. Returns the keys
48	    /// of the agents removed, so the caller can release their locks. A clock
49	    /// that has gone backwards never prunes.
50	    pub(crate) fn prune(&mut self, project: i64, max_idle: Duration) -> Vec<String> {
51	        let Some(agents) = self.by_project.get_mut(&project) else {
52	            return Vec::new();
53	        };
54	        let now = SystemTime::now();
55	        let mut pruned = Vec::new();
56	        agents.retain(|key, a| {
57	            let keep = now
58	                .duration_since(a.last_seen)
59	                .map(|idle| idle < max_idle)
60	                .unwrap_or(true);
61	            if !keep {
62	                pruned.push(key.clone());
63	            }
64	            keep
65	        });
66	        pruned
67	    }
68	
69	    /// Prune silent agents in every project at once. Returns the
70	    /// `(project, key)` pairs removed, so the caller can release their locks
71	    /// and re-project the affected projects.
