1	//! Ensuring the panopt daemon is running.
2	
3	use std::net::{SocketAddr, TcpStream};
4	use std::os::unix::process::CommandExt;
5	use std::path::PathBuf;
6	use std::process::{Command, Stdio};
7	use std::time::Duration;
8	
9	use anyhow::{bail, Context, Result};
10	
11	use crate::paths;
12	
13	/// True if something is accepting connections on `127.0.0.1:port`.
14	fn port_open(port: u16) -> bool {
15	    let addr = SocketAddr::from(([127, 0, 0, 1], port));
16	    TcpStream::connect_timeout(&addr, Duration::from_millis(200)).is_ok()
17	}
18	
19	/// Locate the `panoptd` binary: prefer one next to this executable (a cargo
20	/// build, or a co-installed pair), otherwise trust `PATH`.
21	fn panoptd_path() -> PathBuf {
22	    if let Ok(exe) = std::env::current_exe() {
23	        if let Some(sibling) = exe.parent().map(|d| d.join("panoptd")) {
24	            if sibling.is_file() {
25	                return sibling;
26	            }
27	        }
28	    }
29	    PathBuf::from("panoptd")
30	}
31	
32	/// Ensure `panoptd` is listening on `port`, starting it detached if not.
33	///
34	/// A freshly started daemon is placed in its own session (`setsid`) so it
35	/// outlives the launching terminal and any Zellij session: it is the global
36	/// daemon for every project, never tied to one cockpit.
37	pub fn ensure(port: u16) -> Result<()> {
38	    if port_open(port) {
39	        return Ok(());
40	    }
41	
42	    let log = paths::daemon_log()?;
43	    let out = std::fs::File::create(&log)
44	        .with_context(|| format!("creating daemon log {}", log.display()))?;
45	    let errlog = out.try_clone()?;
46	
47	    eprintln!("panopt: starting panoptd on 127.0.0.1:{port}");
48	    let mut cmd = Command::new(panoptd_path());
49	    cmd.arg("--port")
50	        .arg(port.to_string())
51	        .stdin(Stdio::null())
52	        .stdout(out)
53	        .stderr(errlog);
54	    // SAFETY: `setsid` is async-signal-safe, which is the contract a `pre_exec`
55	    // hook must honour - it runs in the child between fork and exec.
56	    unsafe {
57	        cmd.pre_exec(|| {
58	            if libc::setsid() == -1 {
59	                return Err(std::io::Error::last_os_error());
60	            }
61	            Ok(())
62	        });
63	    }
64	    cmd.spawn()
65	        .context("starting panoptd (is the binary next to panopt, or on PATH?)")?;
66	
