1	//! A minimal synchronous MCP client over Streamable HTTP.
2	//!
3	//! Just enough of the protocol for `panopt todo` to call the daemon's tools:
4	//! one `initialize` handshake, the `initialized` notification, then any number
5	//! of `tools/call`s, over plain localhost HTTP. There is no async runtime -
6	//! `ureq` blocks, which is exactly right for a short-lived CLI.
7	//!
8	//! Streamable HTTP lets the daemon answer a POST with either a bare JSON object
9	//! or a `text/event-stream` body; [`extract_json`] copes with both.
10	
11	use anyhow::{anyhow, bail, Context, Result};
12	use serde_json::{json, Value};
13	
14	/// An open, initialized MCP session against the panopt daemon.
15	pub struct Client {
16	    /// The daemon's `/mcp` endpoint, query string and all.
17	    url: String,
18	    /// The session id the daemon assigned at `initialize`.
19	    session: String,
20	}
21	
22	impl Client {
23	    /// Open a session against `url` (the `/mcp` endpoint with its
24	    /// `?ws=...&observer=1` query already appended) and run the MCP lifecycle
25	    /// handshake, leaving the session ready for [`Client::call`].
26	    pub fn connect(url: &str) -> Result<Client> {
27	        let init = json!({
28	            "jsonrpc": "2.0",
29	            "id": 1,
30	            "method": "initialize",
31	            "params": {
32	                "protocolVersion": "2025-06-18",
33	                "capabilities": {},
34	                "clientInfo": { "name": "panopt-cli", "version": env!("CARGO_PKG_VERSION") }
35	            }
36	        });
37	        let resp = match ureq::post(url)
38	            .set("Content-Type", "application/json")
39	            .set("Accept", "application/json, text/event-stream")
40	            .send_string(&init.to_string())
41	        {
42	            Ok(r) => r,
43	            Err(ureq::Error::Status(code, r)) => bail!(
44	                "daemon rejected initialize (HTTP {code}): {}",
45	                r.into_string().unwrap_or_default()
46	            ),
47	            Err(e) => return Err(e).context("connecting to the panopt daemon"),
48	        };
49	
50	        let session = resp
51	            .header("mcp-session-id")
52	            .ok_or_else(|| anyhow!("daemon returned no MCP session id"))?
53	            .to_string();
54	        let body = resp
55	            .into_string()
56	            .context("reading the initialize response")?;
57	        parse_rpc(&body).context("initialize failed")?;
58	
59	        let client = Client {
60	            url: url.to_string(),
61	            session,
62	        };
63	        let note = json!({ "jsonrpc": "2.0", "method": "notifications/initialized" });
64	        client
65	            .post(&note.to_string())
66	            .context("sending the initialized notification")?;
67	        Ok(client)
68	    }
69	
70	    /// Call tool `name` with `args`. The panopt tools return either a bare
71	    /// string ("ok", a numeric id) or a JSON document; this hands back the
72	    /// parsed JSON when it parses and a JSON string otherwise, so every caller
73	    /// gets one [`Value`].
74	    pub fn call(&self, name: &str, args: Value) -> Result<Value> {
75	        let req = json!({
76	            "jsonrpc": "2.0",
77	            "id": 2,
78	            "method": "tools/call",
79	            "params": { "name": name, "arguments": args }
80	        });
81	        let body = self
82	            .post(&req.to_string())
83	            .with_context(|| format!("calling tool `{name}`"))?;
84	        let result = parse_rpc(&body).with_context(|| format!("tool `{name}` failed"))?;
85	        tool_text(&result)
86	    }
87	
88	    /// Best-effort: ask the daemon to drop this session.
89	    pub fn close(self) {
90	        let _ = ureq::delete(&self.url)
91	            .set("mcp-session-id", &self.session)
92	            .call();
93	    }
94	
95	    /// POST `body` to the endpoint with the session header; return the response
96	    /// body (empty for an accepted notification).
97	    fn post(&self, body: &str) -> Result<String> {
98	        match ureq::post(&self.url)
99	            .set("Content-Type", "application/json")
100	            .set("Accept", "application/json, text/event-stream")
101	            .set("mcp-session-id", &self.session)
102	            .send_string(body)
103	        {
104	            Ok(r) => Ok(r.into_string().unwrap_or_default()),
105	            Err(ureq::Error::Status(code, r)) => bail!(
106	                "daemon returned HTTP {code}: {}",
107	                r.into_string().unwrap_or_default()
108	            ),
109	            Err(e) => Err(e).context("posting to the panopt daemon"),
110	        }
111	    }
112	}
113	
114	/// Extract the JSON-RPC response from a Streamable HTTP body and return its
115	/// `result`, mapping a JSON-RPC `error` onto an `Err`.
116	fn parse_rpc(body: &str) -> Result<Value> {
117	    let json = extract_json(body)?;
118	    if let Some(err) = json.get("error") {
119	        let msg = err
120	            .get("message")
121	            .and_then(Value::as_str)
122	            .unwrap_or("unknown error");
123	        bail!("{msg}");
124	    }
125	    json.get("result")
126	        .cloned()
127	        .ok_or_else(|| anyhow!("response carried neither result nor error"))
128	}
129	
130	/// Pull the JSON-RPC object out of a response body: a body that is already
131	/// JSON is parsed directly; a `text/event-stream` body has its `data:` lines
132	/// concatenated and parsed.
133	fn extract_json(body: &str) -> Result<Value> {
134	    let trimmed = body.trim_start();
135	    if trimmed.starts_with('{') {
136	        return serde_json::from_str(trimmed).context("parsing the JSON response");
137	    }
138	    let mut data = String::new();
139	    for line in body.lines() {
140	        if let Some(rest) = line.strip_prefix("data:") {
141	            data.push_str(rest.strip_prefix(' ').unwrap_or(rest));
142	        }
143	    }
144	    if data.is_empty() {
145	        bail!("empty response from the daemon");
146	    }
147	    serde_json::from_str(&data).context("parsing the SSE data payload")
148	}
149	
150	/// Extract a tool result's first text content, failing when the tool reported
151	/// an error.
152	fn tool_text(result: &Value) -> Result<Value> {
153	    let text = first_text(result);
154	    if result.get("isError").and_then(Value::as_bool) == Some(true) {
155	        bail!(
156	            "{}",
157	            text.unwrap_or_else(|| "tool reported an error".into())
158	        );
159	    }
160	    let text = text.ok_or_else(|| anyhow!("tool returned no text content"))?;
161	    Ok(serde_json::from_str(&text).unwrap_or(Value::String(text)))
162	}
163	
164	/// The first `text` field across a tool result's `content` array.
165	fn first_text(result: &Value) -> Option<String> {
166	    result
167	        .get("content")?
168	        .as_array()?
169	        .iter()
170	        .find_map(|c| c.get("text").and_then(Value::as_str))
171	        .map(str::to_string)
172	}
173	
174	#[cfg(test)]
175	mod tests {
176	    use super::*;
177	
178	    #[test]
179	    fn extract_json_reads_a_plain_body() {
180	        let v = extract_json(r#"{"jsonrpc":"2.0","id":1,"result":{"ok":true}}"#).unwrap();
181	        assert_eq!(v["result"]["ok"], json!(true));
182	    }
183	
184	    #[test]
185	    fn extract_json_reads_an_sse_body() {
186	        let body = "event: message\ndata: {\"jsonrpc\":\"2.0\",\"id\":1,\"result\":42}\n\n";
187	        assert_eq!(extract_json(body).unwrap()["result"], json!(42));
188	    }
189	
190	    #[test]
191	    fn parse_rpc_surfaces_a_jsonrpc_error() {
192	        let body = r#"{"jsonrpc":"2.0","id":1,"error":{"code":-32602,"message":"bad id"}}"#;
193	        let err = parse_rpc(body).unwrap_err();
194	        assert!(err.to_string().contains("bad id"), "{err}");
195	    }
196	
197	    #[test]
198	    fn tool_text_parses_json_content_and_falls_back_to_a_string() {
199	        let json_result = json!({ "content": [ { "type": "text", "text": "[1,2,3]" } ] });
200	        assert_eq!(tool_text(&json_result).unwrap(), json!([1, 2, 3]));
201	
202	        let bare = json!({ "content": [ { "type": "text", "text": "ok" } ] });
203	        assert_eq!(tool_text(&bare).unwrap(), json!("ok"));
204	    }
205	
206	    #[test]
207	    fn tool_text_fails_on_an_error_result() {
208	        let result = json!({ "isError": true, "content": [ { "text": "todo 9 not found" } ] });
209	        let err = tool_text(&result).unwrap_err();
210	        assert!(err.to_string().contains("not found"), "{err}");
211	    }
212	}
213

