        .env("PANOPT_NAME", &id)
        .env("PANOPT_PORT", port.to_string())
        .env("PANOPT_HOST", &host)
        .env("PANOPT_TOKEN", &token)
        .exec();
    Err(err).context("could not exec `claude` (is it installed and on PATH?)")
}

